import React, { useState, useEffect } from "react";
import api from "../../api/axios";
import toast from "react-hot-toast";
import "./Admin.css";

const LEVEL_LABEL = { beginner: "Cơ bản", intermediate: "Trung cấp", advanced: "Nâng cao" };
const EXAM_BADGE = { IELTS: "badge-blue", TOEIC: "badge-green", OTHER: "badge-gray" };

const INIT = { title: "", description: "", teacherId: "", price: 0, level: "beginner", examType: "OTHER", status: "active" };

export default function AdminCourses() {
  const [courses, setCourses] = useState([]);
  const [teachers, setTeachers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [filter, setFilter] = useState("");
  const [modal, setModal] = useState(null); // null | "add" | "edit"
  const [selected, setSelected] = useState(null);
  const [form, setForm] = useState(INIT);

  const fetch = () => {
    setLoading(true);
    Promise.all([api.get("/courses"), api.get("/users")])
      .then(([c, u]) => {
        setCourses(c.data.data || []);
        setTeachers((u.data.data || []).filter(x => x.roleId === 2));
      })
      .catch(() => toast.error("Không thể tải dữ liệu"))
      .finally(() => setLoading(false));
  };

  useEffect(() => { fetch(); }, []);

  const filtered = courses.filter(c =>
    (!search || c.title?.toLowerCase().includes(search.toLowerCase())) &&
    (!filter || c.examType === filter)
  );

  const openAdd = () => { setForm(INIT); setSelected(null); setModal("add"); };
  const openEdit = (c) => {
    setForm({ title: c.title || "", description: c.description || "", teacherId: c.teacherId || "", price: c.price || 0, level: c.level || "beginner", examType: c.examType || "OTHER", status: c.status || "active" });
    setSelected(c); setModal("edit");
  };

  const handleSave = async () => {
    try {
      const payload = { ...form, teacherId: Number(form.teacherId), price: Number(form.price) };
      if (modal === "add") await api.post("/courses", payload);
      else await api.put(`/courses/${selected.id}`, payload);
      toast.success(modal === "add" ? "Tạo khóa học thành công" : "Cập nhật thành công");
      setModal(null); fetch();
    } catch (e) { toast.error(e.response?.data?.message || "Thất bại"); }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Xóa khóa học này?")) return;
    try { await api.delete(`/courses/${id}`); toast.success("Đã xóa"); fetch(); }
    catch { toast.error("Không thể xóa"); }
  };

  return (
    <div className="admin-page fade-in">
      <div className="page-header">
        <h1>Quản lý khóa học</h1>
        <p>Tạo và quản lý các khóa học IELTS, TOEIC</p>
      </div>

      <div className="toolbar">
        <div className="toolbar-left">
          <input className="search-input" placeholder="Tìm khóa học..."
            value={search} onChange={e => setSearch(e.target.value)} />
          <select className="filter-select" value={filter} onChange={e => setFilter(e.target.value)}>
            <option value="">Tất cả loại</option>
            <option value="IELTS">IELTS</option>
            <option value="TOEIC">TOEIC</option>
            <option value="OTHER">Khác</option>
          </select>
        </div>
        <button className="btn btn-primary" onClick={openAdd}>+ Thêm khóa học</button>
      </div>

      <div className="table-wrapper">
        {loading ? <div className="page-loading"><div className="spinner" /></div> : (
          <table className="data-table">
            <thead>
              <tr><th>Khóa học</th><th>Loại</th><th>Cấp độ</th><th>Giáo viên</th><th>Học phí</th><th>Trạng thái</th><th>Thao tác</th></tr>
            </thead>
            <tbody>
              {filtered.length === 0
                ? <tr><td colSpan={7} className="empty-state"><p>Chưa có khóa học nào</p></td></tr>
                : filtered.map(c => (
                  <tr key={c.id}>
                    <td>
                      <div style={{ fontWeight: 500 }}>{c.title}</div>
                      <div style={{ fontSize: "0.78rem", color: "var(--gray-400)", marginTop: 2 }}>
                        {c.description?.slice(0, 60)}{c.description?.length > 60 ? "..." : ""}
                      </div>
                    </td>
                    <td><span className={`badge ${EXAM_BADGE[c.examType] || "badge-gray"}`}>{c.examType}</span></td>
                    <td>{LEVEL_LABEL[c.level] || c.level}</td>
                    <td>{teachers.find(t => t.id === c.teacherId)?.name || "—"}</td>
                    <td>{c.price > 0 ? `${Number(c.price).toLocaleString("vi-VN")}đ` : "Miễn phí"}</td>
                    <td><span className={`badge ${c.status === "active" ? "badge-green" : "badge-red"}`}>
                      {c.status === "active" ? "Hoạt động" : "Ẩn"}
                    </span></td>
                    <td style={{ display: "flex", gap: 6 }}>
                      <button className="btn btn-warning btn-sm" onClick={() => openEdit(c)}>✏️</button>
                      <button className="btn btn-danger btn-sm" onClick={() => handleDelete(c.id)}>🗑️</button>
                    </td>
                  </tr>
                ))
              }
            </tbody>
          </table>
        )}
      </div>

      {modal && (
        <div className="modal-overlay" onClick={() => setModal(null)}>
          <div className="modal" style={{ maxWidth: 560 }} onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3>{modal === "add" ? "Thêm khóa học mới" : "Chỉnh sửa khóa học"}</h3>
              <button className="modal-close" onClick={() => setModal(null)}>✕</button>
            </div>
            <div className="modal-body">
              <div className="form-group"><label>Tên khóa học *</label>
                <input value={form.title} onChange={e => setForm({ ...form, title: e.target.value })} placeholder="VD: IELTS Foundation" />
              </div>
              <div className="form-group"><label>Mô tả</label>
                <textarea rows={3} value={form.description} onChange={e => setForm({ ...form, description: e.target.value })} />
              </div>
              <div className="form-row">
                <div className="form-group"><label>Loại chứng chỉ</label>
                  <select value={form.examType} onChange={e => setForm({ ...form, examType: e.target.value })}>
                    <option value="IELTS">IELTS</option>
                    <option value="TOEIC">TOEIC</option>
                    <option value="OTHER">Tiếng Anh tổng quát</option>
                  </select>
                </div>
                <div className="form-group"><label>Cấp độ</label>
                  <select value={form.level} onChange={e => setForm({ ...form, level: e.target.value })}>
                    <option value="beginner">Cơ bản</option>
                    <option value="intermediate">Trung cấp</option>
                    <option value="advanced">Nâng cao</option>
                  </select>
                </div>
              </div>
              <div className="form-row">
                <div className="form-group"><label>Giáo viên phụ trách</label>
                  <select value={form.teacherId} onChange={e => setForm({ ...form, teacherId: e.target.value })}>
                    <option value="">Chưa phân công</option>
                    {teachers.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                  </select>
                </div>
                <div className="form-group"><label>Học phí (VNĐ)</label>
                  <input type="number" value={form.price} onChange={e => setForm({ ...form, price: e.target.value })} min={0} />
                </div>
              </div>
              <div className="form-group"><label>Trạng thái</label>
                <select value={form.status} onChange={e => setForm({ ...form, status: e.target.value })}>
                  <option value="active">Hoạt động</option>
                  <option value="inactive">Ẩn</option>
                </select>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-ghost" onClick={() => setModal(null)}>Hủy</button>
              <button className="btn btn-primary" onClick={handleSave}>
                {modal === "add" ? "Tạo khóa học" : "Lưu thay đổi"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
